from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
import hashlib
import hmac
import time

app = Flask(__name__)
limiter = Limiter(app, key_func=get_remote_address)

es = Elasticsearch([{'host': 'localhost', 'port': 9200}])

# Rate limiting settings
RATE_LIMIT_PER_IP = 10
RATE_LIMIT_PER_ACCOUNT = 5

# Token expiration time (in seconds)
TOKEN_EXPIRATION_TIME = 300

def generate_token(email):
    return hmac.new(f'secret_key_{email}'.encode(), str(time.time()).encode(), hashlib.sha256).hexdigest()

@app.route('/api/search', methods=['GET'])
@limiter.limit(f'{RATE_LIMIT_PER_IP}/minute')
def search_products():
    q = request.args.get('q')
    if not q:
        return jsonify({'error': 'Missing query parameter'}), 400

    try:
        response = es.search(index='products', body={'query': {'match': {'name': q}}})
        products = [{'id': hit['_source']['id'], 'name': hit['_source']['name']} for hit in response['hits']['hits']]
        return jsonify({'products': products}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)